using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed metadata — returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type: {personInfo.Type.Name}");
Console.WriteLine($"Kind: {personInfo.Kind}");
foreach (var prop in personInfo.Properties)
    Console.WriteLine($"  Property: {prop.Name} ({prop.PropertyType.Name})");

// 2) Probe without throwing — TryGetTypeInfo returns false if unavailable
//    Use a resolver that only handles a specific type to show the "miss" path.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(
        new PersonOnlyResolver())
};

if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"\nPerson metadata found: {found!.Type.Name}");
else
    Console.WriteLine("\nPerson metadata NOT found");

if (limited.TryGetTypeInfo(typeof(Order), out JsonTypeInfo? maybe))
    Console.WriteLine($"Order  metadata found: {maybe!.Type.Name}");
else
    Console.WriteLine("Order  metadata NOT found (no exception thrown)");

// ---------- types ----------
record Person(string FirstName, string LastName, int Age);
record Order(int Id, decimal Total);

// A resolver that intentionally only handles Person
sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) =>
        type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}

